/** MOT (sans accent) → définition masquée. */
export const DEFS5: Map<string, string> = new Map(
  RAW.split('\n').map((l) => {
    const i = l.indexOf('|');
    return [l.slice(0, i), l.slice(i + 1)] as [string, string];
  }),
);
